            }

            // ---- Parte 2: Construcción de la Página (Tu código original) ----
            if (respuesta.pagina_tienda) {
                const tienda = respuesta.pagina_tienda;

                window.abrirModalFormasPago = () => mostrarModalFormasPago(respuesta.formas_pago || [], respuesta.cuenta_transferencia_dia || {});
                window.abrirModalAgencias = () => mostrarModalAgencias(respuesta.contentagencia);

                const botonFormasPago = `<button class="btn btn-outline-primary btn-sm" onclick="abrirModalFormasPago()">Ver Formas de Pago</button>`;
                const botonAgencias = `<button class="btn btn-outline-success btn-sm" onclick="abrirModalAgencias()">Ver Agencias</button>`;

                const htmlHeader = `
                    <h1 class="store-title" id="store-title-trigger" style="user-select: none; -webkit-user-select: none; cursor: pointer;">${tienda.tienda_id}</h1>
                    <div class="store-description">${tienda.descripcion}</div>

                    <div class="presentation-header-inner">
                        <!-- Columna Logo -->
                        <div class="logo-column">
                            <div class="logo-presentacion-container">
                                <div class="logo-presentacion-frame">
                                    <div class="shimmer-overlay"></div>
                                    <img src="${tienda.logo_url}" alt="Logo Tienda" width="200" height="80" class="logo-img-premium logo-metallic-effect" style="max-width: 85%; max-height: 85%; object-fit: contain; z-index: 2;">
                                </div>
                            </div>
                        </div>

                        <!-- Columna Social y Botones -->
                        <div class="social-column">
                            <div class="social-grid-premium">
                                <!-- Categoría: Redes -->
                                <div class="button-group-label">Redes Sociales</div>
                                ${tienda.redes_sociales?.facebook ? `<a href="${tienda.redes_sociales.facebook}" target="_blank" class="btn-premium-social" style="background: #1877f2;"><i class="fa fa-facebook"></i> Facebook</a>` : ""}
                                ${tienda.redes_sociales?.instagram ? `<a href="${tienda.redes_sociales.instagram}" target="_blank" class="btn-premium-social" style="background: linear-gradient(45deg, #f09433 0%, #e6683c 25%, #dc2743 50%, #cc2366 75%, #bc1888 100%);"><i class="fa fa-instagram"></i> Instagram</a>` : ""}
                                ${tienda.redes_sociales?.tiktok ? `<a href="${tienda.redes_sociales.tiktok}" target="_blank" class="btn-premium-social" style="background: #000;"><i class="fa fa-video-camera"></i> TikTok</a>` : ""}

                                <!-- Categoría: Contacto Directo -->
                                <div class="button-group-label" style="margin-top: 8px;">Contacto Directo</div>
                                ${tienda.correo ? `<a href="mailto:${tienda.correo}" target="_blank" class="btn-premium-social" style="background: #ea4335;"><i class="fa fa-envelope"></i> Email</a>` : ""}
                                ${tienda.telefono ? `<a href="tel:${tienda.telefono.replace(/\s+/g, '')}" class="btn-premium-social" style="background: #25d366;"><i class="fa fa-phone"></i> Llamar</a>` : ""}
                                ${tienda.formularios?.cliente ? `<a href="${tienda.formularios.cliente}" target="_blank" class="btn-premium-social" style="background: #34a853;"><i class="fa fa-pencil-square-o"></i> Form. Cliente</a>` : ""}
                                ${tienda.vcard_url ? `<a href="${tienda.vcard_url}" target="_blank" class="btn-premium-social" style="background: var(--primary-cobalt);"><i class="fa fa-user"></i> Mi VCARD</a>` : ""}
                            </div>
