                            <span style="font-weight: 600;">¿Qué opinan de nosotros?</span>
                        </div>
                        <div class="review-stars-interactive">
                            <i class="fa fa-star active"></i><i class="fa fa-star active"></i><i class="fa fa-star active"></i><i class="fa fa-star active"></i><i class="fa fa-star active"></i>
                        </div>
                        <a href="https://search.google.com/local/writereview?placeid=${tienda.google_review.place_id}" target="_blank" class="btn-google-review">Dejar Reseña</a>
