                        <div class="info-tile-premium" style="display: flex; flex-direction: column; gap: 8px; padding: 12px; background: white; border: 1px solid rgba(0, 43, 92, 0.08); box-shadow: 0 4px 15px rgba(0,0,0,0.03);">
