                    // ✅ También marcar tipo_compra = Retiro por defecto
                    const tipoCompraRadio = document.querySelector('input[name="tipo_compra"][value="Retiro"]');
                    if (tipoCompraRadio) {
                        tipoCompraRadio.checked = true;
                        tipoCompraRadio.dispatchEvent(new Event('change'));
