        function confirmarPagoPresencial(nuevoEstado, tituloExito, mensajeExito) {
            const urlParams = new URLSearchParams(window.location.search);
            const idPedido = urlParams.get('id');

            if (!idPedido) {
                Swal.fire("Error", "No se identificó el pedido.", "error");
                return;
            }

            toggleLoader(true);
            makeAjaxCall(
                `${url_final_venta}exec`,
                {
                    op: "confirmar_pago_presencial",
                    idpedido: idPedido,
                    nuevoEstado: nuevoEstado
                },
                function (respuesta) {
                    toggleLoader(false);
                    Swal.fire(tituloExito, mensajeExito, "success").then(() => {
                        location.reload();
                    });
                },
                function (err) {
                    toggleLoader(false);
                    Swal.fire("Error", err.message || "Error al procesar", "error");
                }
            );
        }

