        function gestionarBloqueoCampos(bloquear) {
            const selectores = [
                '#txt_nombre_real', '#txt_telefono', 
                '#txt_rut', '#txt_condicion_fiscal',
                '#txt_provincia', '#txt_municipio', '#txt_localidad',
