            ];

            // v15.7 - Bloquear además los selectores de tipo de compra y envío
            document.querySelectorAll('input[name="tipo_compra"]').forEach(r => r.disabled = bloquear);
            document.querySelectorAll('input[name="tipo_envio"]').forEach(r => r.disabled = bloquear);

            selectores.forEach(sel => {
                const el = document.querySelector(sel);
                if (el) {
                    if (el.tagName === 'SELECT') {
                        el.disabled = bloquear;
                    } else {
                        el.readOnly = bloquear;
                    }
                }
            });
        }

