        function actualizarSimboloAddonPDF() {
            const tipo = document.getElementById("tipoRecargoPDF")?.value || 'porcentaje';
            const sim = (tipo === 'porcentaje') ? '%' : '+$';
            document.querySelectorAll('.addon-simbolo-pdf').forEach(el => el.innerText = sim);
            // Actualizar placeholders o valores sugeridos si cambian el tipo
            const esFijo = (tipo === 'monto_fijo');
            document.querySelectorAll('.input-var-pdf').forEach(inp => {
                const varName = (inp.getAttribute('data-variedad') || '').toLowerCase();
                if (esFijo) {
                    if (parseFloat(inp.value) < 100) inp.value = 1000;
                } else {
                    if (parseFloat(inp.value) >= 100) {
                        if (varName.includes('menor') || varName.includes('unidad')) inp.value = 25;
                        else if (varName.includes('curva') || varName.includes('pack')) inp.value = 15;
                        else inp.value = 10;
                    }
                }
            });
            const genInp = document.getElementById("recargo_general");
            if (genInp) {
                if (esFijo && parseFloat(genInp.value) < 100) genInp.value = 1000;
                else if (!esFijo && parseFloat(genInp.value) >= 100) genInp.value = 20;
            }
        }

        function renderizarInputsVariedadesPDF(nomCat) {
            const cont = document.getElementById("divContenedorVariedadesPDF");
            if (!cont) return;
            cont.innerHTML = "";

            try {
                const configCompleta = JSON.parse(localStorage.getItem('configuracion_pagina') || '{}');
                const todasCategorias = (configCompleta?.content || []).flatMap(padre => padre.categorias || []);
                let productos = [];

                if (nomCat && nomCat !== "") {
                    const catObj = todasCategorias.find(c => c.nombre === nomCat);
                    productos = catObj ? (catObj.producto || []) : [];
                } else {
                    todasCategorias.forEach(c => {
                        (c.producto || []).forEach(p => productos.push(p));
                    });
                }

                const setVariedades = new Set();
                productos.forEach(p => {
                    if (Array.isArray(p.variedad)) {
                        p.variedad.forEach(v => {
                            const nom = String(v.variedad || "").trim();
                            if (nom) setVariedades.add(nom);
                        });
                    }
                });

                if (setVariedades.size === 0) {
                    ["Docena", "Curva", "Menor"].forEach(v => setVariedades.add(v));
                }

                const row = document.createElement("div");
                row.className = "row g-2 mb-1";

                const tipoActual = document.getElementById("tipoRecargoPDF")?.value || 'porcentaje';
                const simInicial = (tipoActual === 'porcentaje') ? '%' : '+$';
                const esFijo = (tipoActual === 'monto_fijo');

                Array.from(setVariedades).forEach((varName) => {
                    const col = document.createElement("div");
                    col.className = "col-12 col-sm-6 mb-2";

                    let defVal = esFijo ? 1000 : 20;
                    if (!esFijo) {
                        const low = varName.toLowerCase();
                        if (low.includes("corte") || low.includes("fardo") || low.includes("caja") || low.includes("docena") || low.includes("mayor") || low.includes("x12") || low.includes("combo")) {
                            defVal = 10;
                        } else if (low.includes("curva") || low.includes("pack") || low.includes("surti") || low.includes("media")) {
                            defVal = 15;
                        } else if (low.includes("menor") || low.includes("unidad") || low.includes("c/u") || low.includes("x1")) {
                            defVal = 25;
                        }
                    }

                    const colorBg = typeof obtenerColor === 'function' ? obtenerColor(varName) : '#0284c7';

                    col.innerHTML = `
                        <label class='form-label mb-1 d-flex align-items-center' style='font-size: 0.8rem; font-weight: 600; color: #334155;'>
                            <span class='badge me-1' style='background-color: ${colorBg}; color: #fff; font-size: 0.7rem;'>●</span>
                            <span class='text-truncate' title='${varName}'>${varName}:</span>
                        </label>
                        <div class='input-group input-group-sm shadow-sm'>
                            <input type='number' class='form-control fw-bold text-primary input-var-pdf' data-variedad='${varName}' value='${defVal}' step='any'/>
                            <span class='input-group-text addon-simbolo-pdf fw-bold text-dark' style='min-width: 42px; justify-content: center; background-color: #e2e8f0;'>${simInicial}</span>
                        </div>
                    `;
                    row.appendChild(col);
                });

                const colDef = document.createElement("div");
                colDef.className = "col-12 col-sm-6 mb-2";
                colDef.innerHTML = `
                    <label class='form-label mb-1 d-flex align-items-center' style='font-size: 0.8rem; font-weight: 600; color: #64748b;'>
                        <span class='badge me-1 bg-secondary' style='font-size: 0.7rem;'>●</span>
                        <span>General / Resto:</span>
                    </label>
                    <div class='input-group input-group-sm shadow-sm'>
                        <input type='number' class='form-control fw-bold text-secondary' id='recargo_general' value='${esFijo ? 1000 : 20}' step='any'/>
                        <span class='input-group-text addon-simbolo-pdf fw-bold text-dark' style='min-width: 42px; justify-content: center; background-color: #e2e8f0;'>${simInicial}</span>
                    </div>
                `;
                row.appendChild(colDef);

                cont.appendChild(row);
            } catch (err) {
                console.warn("Error al renderizar inputs dinámicos de variedad:", err);
            }
        }

        async function cargarImagenYConvertirAJpegBase64(url) {
            if (!url || typeof url !== 'string' || url.trim() === '') return null;

            // Transformación mágica: Convertir enlaces de Drive (thumbnail?id=, uc?id=, etc) al CDN de Google con CORS abierto
            let urlCors = url.trim();
            const matchId = urlCors.match(/[?&]id=([a-zA-Z0-9_-]{25,})/i) || urlCors.match(/\/d\/([a-zA-Z0-9_-]{25,})/i);
            if (matchId && matchId[1]) {
                urlCors = `https://lh3.googleusercontent.com/d/${matchId[1]}=s600-rw`;
            }

            return new Promise((resolve) => {
                const img = new Image();
                img.crossOrigin = "Anonymous"; // Aprovechamos CORS abierto de Google CDN (lh3)
                img.onload = () => {
                    try {
                        const canvas = document.createElement("canvas");
                        canvas.width = img.naturalWidth || 300;
                        canvas.height = img.naturalHeight || 300;
                        const ctx = canvas.getContext("2d");
                        ctx.fillStyle = "#FFFFFF"; // Fondo blanco para transparencia
                        ctx.fillRect(0, 0, canvas.width, canvas.height);
                        ctx.drawImage(img, 0, 0);
                        const dataUrl = canvas.toDataURL("image/jpeg", 0.82);
                        resolve(dataUrl);
                    } catch (e) {
                        console.warn("⚠️ Error en canvas toDataURL para PDF:", e);
                        resolve(null);
                    }
                };
                img.onerror = () => {
                    console.warn("⚠️ Falló carga con lh3 CDN, intentando URL alternativa:", urlCors);
                    const imgFallback = new Image();
                    imgFallback.crossOrigin = "Anonymous";
                    imgFallback.onload = () => {
                        try {
                            const canvas = document.createElement("canvas");
                            canvas.width = imgFallback.naturalWidth || 300;
                            canvas.height = imgFallback.naturalHeight || 300;
                            const ctx = canvas.getContext("2d");
                            ctx.fillStyle = "#FFFFFF";
                            ctx.fillRect(0, 0, canvas.width, canvas.height);
                            ctx.drawImage(imgFallback, 0, 0);
                            resolve(canvas.toDataURL("image/jpeg", 0.82));
                        } catch (err) {
                            resolve(null);
                        }
                    };
                    imgFallback.onerror = () => {
                        // Último recurso sin crossOrigin por si el navegador lo admite desde caché
                        const imgNoCors = new Image();
                        imgNoCors.onload = () => {
                            try {
                                const canvas = document.createElement("canvas");
                                canvas.width = imgNoCors.naturalWidth || 300;
                                canvas.height = imgNoCors.naturalHeight || 300;
                                const ctx = canvas.getContext("2d");
                                ctx.fillStyle = "#FFFFFF";
                                ctx.fillRect(0, 0, canvas.width, canvas.height);
                                ctx.drawImage(imgNoCors, 0, 0);
                                resolve(canvas.toDataURL("image/jpeg", 0.82));
                            } catch (e2) { resolve(null); }
                        };
                        imgNoCors.onerror = () => resolve(null);
                        imgNoCors.src = url;
                    };
                    imgFallback.src = `https://lh3.googleusercontent.com/d/${matchId ? matchId[1] : ''}`;
                };
                img.src = urlCors;
            });
        }

        function obtenerListaMetadataPDF(prod) {
            const desc = prod.descripcion || {};
            const items = [];

            const addAttr = (label, val) => {
                if (!val || val === '-' || val === 'undefined' || val === 'null' || val === '' || (Array.isArray(val) && !val.length)) return;
                items.push({
                    text: [
                        { text: `• ${label}: `, bold: true, fontSize: 8, color: '#002b5c' },
                        { text: String(val), bold: false, fontSize: 8, color: '#333333' }
                    ],
                    margin: [0, 1.5, 0, 1.5]
                });
            };

            const formatObj = (v) => {
                if (v === null || v === undefined) return '';
                if (typeof v === 'object') {
                    return v.nombre || v.label || v.etiqueta || v.talle || v.valor || JSON.stringify(v);
                }
                return String(v);
            };

            const getVal = (key) => {
                if (desc[key]) {
                    if (typeof desc[key] === 'object' && desc[key].valor) return formatObj(desc[key].valor);
                    if (typeof desc[key] === 'object' && Array.isArray(desc[key].valores)) {
                        return desc[key].valores.map(formatObj).join(', ');
                    }
                    return formatObj(desc[key]);
                }
                if (prod[key]) {
                    if (Array.isArray(prod[key])) {
                        return prod[key].map(formatObj).join(', ');
                    }
                    if (typeof prod[key] === 'object' && prod[key].valor) return formatObj(prod[key].valor);
                    return formatObj(prod[key]);
                }
                return null;
            };

            addAttr('Modelo', getVal('modelo'));
            addAttr('Marca', getVal('marca'));
            addAttr('Género', getVal('genero'));
            addAttr('Material', getVal('material'));
            addAttr('Temporada', getVal('temporada'));
            addAttr('Estilo', getVal('estilo'));
            addAttr('Edad', getVal('grupo_edad'));

            const renderBadgesAttr = (label, arrValores, isColor) => {
                if (!arrValores || !arrValores.length || (arrValores.length === 1 && !arrValores[0])) return;
                const spans = [ { text: `• ${label}: `, bold: true, fontSize: 8, color: '#002b5c' } ];

                arrValores.forEach((item, idx) => {
                    const valStr = typeof item === 'object' ? (item.nombre || item.valor || String(item)) : String(item);
                    if (!valStr || valStr === '-' || valStr === 'undefined' || valStr === 'null') return;

                    let bg = '#e2e8f0';
                    let fg = '#334155';

                    if (isColor) {
                        let hex = (typeof item === 'object' && item.hex && item.hex !== 'transparent') ? item.hex : null;
                        const nom = valStr.toLowerCase().trim();
                        if (!hex) {
                            if (nom === 'surtido' || nom === 'variados') hex = '#6854fa';
                            else if (nom === 'negro') hex = '#000000';
                            else if (nom === 'blanco') hex = '#f8fafc';
                            else if (nom === 'rojo' || nom.includes('bordo') || nom.includes('bordó')) hex = '#991b1b';
                            else if (nom.includes('azul')) hex = '#1e3a8a';
                            else if (nom === 'gris') hex = '#475569';
                            else if (nom.includes('marron') || nom.includes('marrón')) hex = '#78350f';
                            else if (nom.includes('verde')) hex = '#365314';
                            else if (nom.includes('rosa')) hex = '#db2777';
                            else if (nom === 'amarillo') hex = '#ca8a04';
                            else hex = '#334155';
                        }
                        bg = hex;
                        fg = (bg === '#ffffff' || bg === '#f8fafc' || bg === '#fff' || bg === '#ffff00' || bg === '#f1f5f9') ? '#1e293b' : '#ffffff';
                    }

                    spans.push({
                        text: `  ${valStr.trim()}  `,
                        fontSize: 7,
                        bold: true,
                        color: fg,
                        background: bg
                    });
                    if (idx < arrValores.length - 1) spans.push({ text: ' ' });
                });
                if (spans.length > 1) {
                    items.push({ text: spans, margin: [0, 2, 0, 2] });
                }
            };

            // Talles
            let arrTalles = [];
            if (desc.talles && Array.isArray(desc.talles.valores)) arrTalles = desc.talles.valores;
            else if (prod.talles && Array.isArray(prod.talles)) arrTalles = prod.talles;
            else if (getVal('talles')) arrTalles = String(getVal('talles')).split(',').map(s => s.trim());
            if (!arrTalles || !arrTalles.length) arrTalles = ['Consultar'];
            renderBadgesAttr('Talles', arrTalles, false);

            // Colores
            let arrColores = [];
            if (desc.colores && Array.isArray(desc.colores.valores)) arrColores = desc.colores.valores;
            else if (prod.colores && Array.isArray(prod.colores)) arrColores = prod.colores;
            else if (getVal('colores')) arrColores = String(getVal('colores')).split(',').map(s => s.trim());
            if (!arrColores || !arrColores.length) arrColores = ['Variados'];
            renderBadgesAttr('Colores', arrColores, true);

            const stockVal = getVal('stock');
            const actVal = getVal('ultima_actualizacion') || (prod.fecha_carga ? String(prod.fecha_carga).slice(0,10) : null);
            if (stockVal || actVal) {
                items.push({
                    text: [
                        { text: `Stock: `, bold: true, fontSize: 7.5, color: '#64748b' },
                        { text: `${stockVal || '-'}   `, fontSize: 7.5, color: '#64748b' },
                        { text: `Act: `, bold: true, fontSize: 7.5, color: '#64748b' },
                        { text: `${actVal || '-'}`, fontSize: 7.5, color: '#64748b' }
                    ],
                    margin: [0, 4, 0, 0]
                });
            }

            return items;
        }

        function calcularYFormatearPreciosPDF(producto, modoPrecio, tipoRecargo, mapaRecargos) {
            if (modoPrecio === 'ciego') {
                return { text: '💬 Cotizar precio y compra mínima por privado', fontSize: 9.5, bold: true, color: '#64748b', alignment: 'center', margin: [0, 4, 0, 4] };
            }
            const varieties = producto.variedad || [];
            if (!varieties.length) {
                let pBase = parseFloat(producto.precio) || 0;
                const minCompra = parseInt(producto.minima) || 1;
                if (modoPrecio === 'recargo' && pBase > 0) {
                    const val = (mapaRecargos && mapaRecargos.general !== undefined) ? parseFloat(mapaRecargos.general) : 0;
                    if (tipoRecargo === 'porcentaje') pBase = pBase * (1 + val / 100);
                    else if (tipoRecargo === 'monto_fijo' || tipoRecargo === 'fijo') pBase = pBase + val;
                    else if (tipoRecargo === 'multiplicador' && val > 0) pBase = pBase * val;
                }
                const pTotal = pBase * minCompra;
                const simbolo = producto.moneda || '$';
                const pFmt = typeof formatMoneda === 'function' ? formatMoneda(pBase, simbolo) : `${simbolo}${pBase.toFixed(2)}`;
                const pTotalFmt = typeof formatMoneda === 'function' ? formatMoneda(pTotal, simbolo) : `${simbolo}${pTotal.toFixed(2)}`;
                return {
                    text: [
                        { text: `• PRECIO OFICIAL: `, bold: true, fontSize: 8.5, color: '#002b5c' },
                        { text: `${pFmt} c/u `, bold: true, fontSize: 9.5, color: modoPrecio === 'recargo' ? '#0284c7' : '#002b5c' },
                        { text: `(Mínimo ${minCompra} un. = `, fontSize: 7.5, color: '#64748b' },
                        { text: `${pTotalFmt}`, bold: true, fontSize: 8, color: '#334155' },
                        { text: `)`, fontSize: 7.5, color: '#64748b' }
                    ],
                    alignment: 'left',
                    margin: [0, 2, 0, 2]
                };
            }

            const lineasPrecio = varieties.map(v => {
                let precioUnit = parseFloat(v.precio) || 0;
                const minCompra = parseInt(v.minima) || 1;
                const nombreVar = v.variedad ? String(v.variedad).trim() : 'PRECIO';
                const nomLower = nombreVar.toLowerCase();

                if (modoPrecio === 'recargo' && precioUnit > 0 && mapaRecargos) {
                    let val = mapaRecargos[nombreVar];
                    if (val === undefined) val = mapaRecargos[nomLower];
                    if (val === undefined) {
                        let fallbackGen = mapaRecargos.general !== undefined ? mapaRecargos.general : 0;
                        if (nomLower.includes('docena') || nomLower.includes('mayor') || nomLower.includes('x12') || nomLower.includes('box') || nomLower.includes('corte') || nomLower.includes('fardo') || nomLower.includes('caja')) {
                            val = mapaRecargos.docena !== undefined ? mapaRecargos.docena : fallbackGen;
                        } else if (nomLower.includes('curva') || nomLower.includes('pack') || nomLower.includes('surti') || nomLower.includes('media') || nomLower.includes('combo')) {
                            val = mapaRecargos.curva !== undefined ? mapaRecargos.curva : fallbackGen;
                        } else if (nomLower.includes('menor') || nomLower.includes('unidad') || nomLower.includes('c/u') || nomLower.includes('x1')) {
                            val = mapaRecargos.menor !== undefined ? mapaRecargos.menor : fallbackGen;
                        } else {
                            val = fallbackGen;
                        }
                    }

                    const numVal = parseFloat(val) || 0;
                    if (tipoRecargo === 'porcentaje') {
                        precioUnit = precioUnit * (1 + numVal / 100);
                    } else if (tipoRecargo === 'monto_fijo' || tipoRecargo === 'fijo') {
                        precioUnit = precioUnit + numVal;
                    } else if (tipoRecargo === 'multiplicador' && numVal > 0) {
                        precioUnit = precioUnit * numVal;
                    }
                }

                const precioTotalMin = precioUnit * minCompra;
                const simbolo = v.moneda || '$';
                const pUnitFmt = typeof formatMoneda === 'function' ? formatMoneda(precioUnit, simbolo) : `${simbolo}${precioUnit.toFixed(2)}`;
                const pTotalFmt = typeof formatMoneda === 'function' ? formatMoneda(precioTotalMin, simbolo) : `${simbolo}${precioTotalMin.toFixed(2)}`;

                return {
                    text: [
                        { text: `• ${nombreVar.toUpperCase()}: `, bold: true, fontSize: 8.5, color: '#002b5c' },
                        { text: `${pUnitFmt} c/u `, bold: true, fontSize: 9.5, color: modoPrecio === 'recargo' ? '#0284c7' : '#002b5c' },
                        { text: `(Mínimo ${minCompra} un. = `, fontSize: 7.5, color: '#64748b' },
                        { text: `${pTotalFmt}`, bold: true, fontSize: 8, color: '#334155' },
                        { text: `)`, fontSize: 7.5, color: '#64748b' }
                    ],
                    margin: [0, 2, 0, 2],
                    alignment: 'left'
                };
            });

            return { stack: lineasPrecio, alignment: 'left' };
        }

        function crearCeldaProductoPDF(prod, modoPrecio, tipoRecargo, mapaRecargos) {
            if (!prod) return null;

            let imgObj = { text: 'Sin imagen disponible', fontSize: 8, color: '#999999', alignment: 'center', margin: [0, 40, 0, 40] };
            if (prod._base64Img) {
                imgObj = {
                    image: prod._base64Img,
                    width: 140,
                    alignment: 'center',
                    margin: [0, 0, 0, 4]
                };
            }

            const preciosObj = calcularYFormatearPreciosPDF(prod, modoPrecio, tipoRecargo, mapaRecargos);

            let linkDrive = null;
            if (prod.carpeta_id && String(prod.carpeta_id).trim() !== '' && String(prod.carpeta_id) !== 'undefined') {
                linkDrive = {
                    text: 'Ver fotos en Google Drive',
                    link: `https://drive.google.com/drive/folders/${String(prod.carpeta_id).trim()}`,
                    color: '#0d6efd',
                    decoration: 'underline',
                    fontSize: 8.5,
                    bold: true,
                    alignment: 'center',
                    margin: [0, 8, 0, 0]
                };
            }

            const listaMetadata = obtenerListaMetadataPDF(prod);
            const nombreProd = prod.nombre || prod.codigo || 'Producto';
            const skuProd = prod.codigo ? `Código SKU: [ ${prod.codigo} ]` : '';

            return {
                table: {
                    widths: ['100%'],
                    body: [
                        [
                            {
                                stack: [
                                    // CABECERA DEL PRODUCTO
                                    {
                                        text: nombreProd.toUpperCase(),
                                        style: 'prodTitle',
                                        margin: [0, 0, 0, 3]
                                    },
                                    skuProd ? {
                                        text: skuProd,
                                        fontSize: 8,
                                        bold: true,
                                        color: '#475569',
                                        background: '#f1f5f9',
                                        margin: [0, 0, 0, 8]
                                    } : { text: '', margin: [0,0,0,2] },
                                    // CUERPO EN 2 COLUMNAS (68% Izq: Specs & Precios, 32% Der: Foto)
                                    {
                                        columns: [
                                            {
                                                width: '68%',
                                                stack: [
                                                    { stack: listaMetadata, margin: [0, 0, 10, 8] },
                                                    {
                                                        table: {
                                                            widths: ['100%'],
                                                            body: [
                                                                [{ stack: [preciosObj], fillColor: '#f8fafc', margin: [6, 6, 6, 6] }]
                                                            ]
                                                        },
                                                        layout: {
                                                            hLineWidth: function() { return 0.5; },
                                                            vLineWidth: function() { return 0.5; },
                                                            hLineColor: function() { return '#cbd5e1'; },
                                                            vLineColor: function() { return '#cbd5e1'; }
                                                        }
                                                    }
                                                ],
                                                margin: [0, 0, 10, 0]
                                            },
                                            {
                                                width: '32%',
                                                stack: [
                                                    {
                                                        table: {
                                                            widths: ['100%'],
                                                            body: [
                                                                [{ text: 'PORTADA', fontSize: 7, bold: true, color: '#000000', fillColor: '#ffc107', alignment: 'center', margin: [0, 2, 0, 2] }],
                                                                [{ stack: [imgObj], alignment: 'center', margin: [4, 6, 4, 4] }]
                                                            ]
                                                        },
                                                        layout: {
                                                            hLineWidth: function() { return 0.5; },
                                                            vLineWidth: function() { return 0.5; },
                                                            hLineColor: function() { return '#e2e8f0'; },
                                                            vLineColor: function() { return '#e2e8f0'; }
                                                        }
                                                    },
                                                    linkDrive ? linkDrive : { text: '' }
                                                ],
                                                alignment: 'center'
                                            }
                                        ]
                                    }
                                ],
                                margin: [12, 12, 12, 12],
                                fillColor: '#ffffff'
                            }
                        ]
                    ]
                },
                layout: {
                    hLineWidth: function() { return 1; },
                    vLineWidth: function() { return 1; },
                    hLineColor: function() { return '#cbd5e1'; },
                    vLineColor: function() { return '#cbd5e1'; },
                    paddingLeft: function() { return 0; },
                    paddingRight: function() { return 0; },
                    paddingTop: function() { return 0; },
                    paddingBottom: function() { return 0; }
                },
                margin: [0, 0, 0, 14],
                border: [false, false, false, false],
                unbreakable: true
            };
        }

        async function ejecutarGeneracionPDF() {
            if (typeof pdfMake === 'undefined') {
                Swal.fire("Error", "La librería pdfmake no está disponible en este momento.", "error");
                return;
            }

            const modoPrecio = document.querySelector('input[name="modoPrecioPDF"]:checked')?.value || 'oficial';
            const tipoRecargo = document.getElementById("tipoRecargoPDF")?.value || 'porcentaje';
            const recargoGeneral = parseFloat(document.getElementById("recargo_general")?.value) || 0;
            const mapaRecargos = {
                general: recargoGeneral,
                docena: recargoGeneral,
                curva: recargoGeneral,
                menor: recargoGeneral
            };
            document.querySelectorAll('#divContenedorVariedadesPDF input[data-variedad]').forEach(inp => {
                const varName = inp.getAttribute('data-variedad').trim();
                const numVal = parseFloat(inp.value) || 0;
                mapaRecargos[varName] = numVal;
                mapaRecargos[varName.toLowerCase()] = numVal;
                const low = varName.toLowerCase();
                if (low.includes('docena') || low.includes('mayor') || low.includes('x12') || low.includes('caja') || low.includes('fardo') || low.includes('corte')) {
                    mapaRecargos.docena = numVal;
                } else if (low.includes('curva') || low.includes('pack') || low.includes('surti') || low.includes('combo')) {
                    mapaRecargos.curva = numVal;
                } else if (low.includes('menor') || low.includes('unidad') || low.includes('c/u') || low.includes('x1')) {
                    mapaRecargos.menor = numVal;
                }
            });
            const nomCat = window._categoriaSeleccionadaPDF;

            // Cerrar modal de configuración
            if (typeof $ !== 'undefined' && $.fn.modal) {
                $('#modalConfigPDF').modal('hide');
            } else {
                const modEl = document.getElementById('modalConfigPDF');
                if (modEl && typeof bootstrap !== 'undefined') {
                    const modInst = bootstrap.Modal.getInstance(modEl);
                    if (modInst) modInst.hide();
                }
            }

            Swal.fire({
                title: 'Generando Catálogo PDF...',
                text: 'Descargando miniaturas WebP del CDN y maquetando el documento en formato 1 tarjeta por fila para máxima calidad. Por favor espera unos segundos...',
                allowOutsideClick: false,
                didOpen: () => {
                    Swal.showLoading();
                }
            });

            try {
                const configCompleta = JSON.parse(localStorage.getItem('configuracion_pagina'));
                const todasCategorias = (configCompleta?.content || []).flatMap(padre => padre.categorias || []);
                let productos = [];
                let tituloDoc = "CATÁLOGO DE PRODUCTOS";
                let subtituloDoc = "COLECCIÓN COMPLETA";

                if (nomCat && nomCat !== "") {
                    const catObj = todasCategorias.find(c => c.nombre === nomCat);
                    productos = catObj ? (catObj.producto || []) : [];
                    tituloDoc = `COLECCIÓN: ${nomCat.toUpperCase()}`;
                    subtituloDoc = "Catálogo Oficial de Productos";
                } else {
                    const skuSet = new Set();
                    todasCategorias.forEach(c => {
                        (c.producto || []).forEach(p => {
                            if (!skuSet.has(p.codigo)) {
                                skuSet.add(p.codigo);
                                productos.push({ ...p, _catNombre: c.nombre });
                            }
                        });
                    });
                }

                if (!productos.length) {
                    Swal.close();
                    Swal.fire("Atención", "No se encontraron productos en esta categoría para exportar.", "warning");
                    return;
                }

                // Descargar imágenes en paralelo via Canvas (Aprovechando CDN Google y CORS)
                const productosConImg = [];
                for (let p of productos) {
                    let urlImg = "";
                    if (Array.isArray(p.imagen) && p.imagen.length > 0) {
                        const sorted = [...p.imagen].sort((a, b) => {
                            if (a.portada && !b.portada) return -1;
                            if (!a.portada && b.portada) return 1;
                            return (parseInt(a.orden) || 999) - (parseInt(b.orden) || 999);
                        });
                        urlImg = sorted[0].thumbnail_url || sorted[0].url || "";
                    } else if (typeof p.imagen === 'string') {
                        urlImg = p.imagen;
                    } else {
                        urlImg = p.thumbnail_url || p.url || "";
                    }

                    let base64 = null;
                    if (urlImg) {
                        base64 = await cargarImagenYConvertirAJpegBase64(urlImg);
                    }
                    productosConImg.push({ ...p, _base64Img: base64 });
                }

                // Construir lista de tarjetas e índice si es catálogo completo
                const listaTarjetas = [];
                let indiceElementos = [];

                if (nomCat && nomCat !== "") {
                    for (let p of productosConImg) {
                        const celda = crearCeldaProductoPDF(p, modoPrecio, tipoRecargo, mapaRecargos);
                        if (celda && celda.table) {
                            listaTarjetas.push(celda);
                        }
                    }
                } else {
                    const botonesIdx = [];
                    let catIdx = 0;
                    todasCategorias.forEach((c, idx) => {
                        const prodsCat = productosConImg.filter(p => p._catNombre === c.nombre);
                        if (prodsCat && prodsCat.length > 0) {
                            const anchorId = `cat_sec_${idx}`;
                            botonesIdx.push({
                                text: `   [ ${c.nombre.toUpperCase()} ]   `,
                                linkToDestination: anchorId,
                                fontSize: 8.5,
                                bold: true,
                                color: '#ffffff',
                                background: '#0284c7'
                            });
                            botonesIdx.push({ text: '  ' });

                            if (catIdx > 0) {
                                listaTarjetas.push({ text: '', pageBreak: 'before' });
                            }
                            listaTarjetas.push({
                                table: {
                                    widths: ['100%'],
                                    body: [
                                        [ { text: `CATEGORÍA: ${c.nombre.toUpperCase()}`, fontSize: 13, bold: true, color: '#ffffff', alignment: 'center', margin: [0, 6, 0, 6] } ]
                                    ]
                                },
                                layout: 'noBorders',
                                fillColor: '#002b5c',
                                id: anchorId,
                                margin: [0, 0, 0, 15]
                            });

                            prodsCat.forEach(p => {
                                const celda = crearCeldaProductoPDF(p, modoPrecio, tipoRecargo, mapaRecargos);
                                if (celda && celda.table) listaTarjetas.push(celda);
                            });
                            catIdx++;
                        }
                    });

                    if (botonesIdx.length > 0) {
                        indiceElementos = [
                            { text: 'ÍNDICE RÁPIDO DE CATEGORÍAS (Haz clic en un botón para saltar directamente):', fontSize: 8.5, bold: true, color: '#475569', alignment: 'center', margin: [0, 0, 0, 8] },
                            { text: botonesIdx, alignment: 'center', margin: [0, 0, 0, 18] }
                        ];
                    }
                }

                const nombreTienda = configCompleta?.nombre_tienda || document.title || "Tienda Mayorista";
                const nombreArchivo = `${(nomCat || 'Catalogo_Completo').replace(/[^a-zA-Z0-9]/g, '_')}_${new Date().toISOString().slice(0,10)}.pdf`;

                const docDefinition = {
                    pageSize: 'A4',
                    pageMargins: [30, 45, 30, 45],
                    header: function(currentPage, pageCount) {
                        return {
                            text: `${nombreTienda}  |  ${nomCat ? 'Categoría: ' + nomCat : 'Catálogo Completo'}`,
                            alignment: 'right',
                            margin: [30, 15, 30, 0],
                            fontSize: 8,
                            color: '#888888'
                        };
                    },
                    footer: function(currentPage, pageCount) {
                        return {
                            columns: [
                                { text: 'WhatsApp: Consultas y Pedidos', alignment: 'left', margin: [30, 10, 0, 0], fontSize: 9, bold: true, color: '#25D366' },
                                { text: `Página ${currentPage} de ${pageCount}`, alignment: 'right', margin: [0, 10, 30, 0], fontSize: 9, color: '#666666' }
                            ]
                        };
                    },
                    content: [
                        { text: nombreTienda.toUpperCase(), style: 'mainTitle', alignment: 'center' },
                        { text: tituloDoc, style: 'subTitle', alignment: 'center' },
                        { text: `Fecha de emisión: ${new Date().toLocaleDateString('es-AR')}  •  ${productos.length} Productos`, style: 'dateStyle', alignment: 'center', margin: [0, 0, 0, indiceElementos.length ? 12 : 20] },
                        ...indiceElementos,
                        ...listaTarjetas
                    ],
                    styles: {
                        mainTitle: { fontSize: 20, bold: true, color: '#002b5c', margin: [0, 0, 0, 4] },
                        subTitle: { fontSize: 13, bold: true, color: '#333333', margin: [0, 0, 0, 4] },
                        dateStyle: { fontSize: 8.5, italic: true, color: '#64748b' },
                        prodTitle: { fontSize: 11, bold: true, color: '#002b5c', margin: [0, 0, 0, 2] },
                        prodSku: { fontSize: 8, bold: true, color: '#475569', margin: [0, 0, 0, 4] },
                        prodDetails: { fontSize: 8, color: '#444444', margin: [0, 0, 0, 4] }
                    }
                };

                pdfMake.createPdf(docDefinition).download(nombreArchivo);
                Swal.close();
                Swal.fire({
                    icon: 'success',
                    title: '¡Catálogo PDF Generado!',
                    text: `El archivo ${nombreArchivo} ha sido descargado con éxito.`,
                    timer: 2500,
                    showConfirmButton: false
                });
            } catch (err) {
                console.error("❌ Error generando PDF:", err);
                Swal.close();
                Swal.fire("Error", "Ocurrió un problema al generar el catálogo PDF: " + err.message, "error");
            }
        }
        //
